def translate_tree(tree):
    mapping = {'T': 'igual', 'S': 'menor', 'L': 'maior'}
    
    if not isinstance(tree, dict):
        return tree
    
    new_tree = {}
    for k, v in tree.items():
        new_key = mapping.get(k, k)
        
        if isinstance(v, dict):
            new_tree[new_key] = translate_tree(v)
        else:
            new_tree[new_key] = v
            
    return new_tree

